struct ContentView: View {
    let websiteURL = URL(string: "https://www.apple.com")! // Replace with your mobile website URL
    let jsMessageHandlerName = "nativeApp" // This name must match what your JavaScript uses

    @State private var receivedMessage: String = "No message yet."

    var body: some View {
        VStack {
            Text("Received from Web: \(receivedMessage)")
                .padding()

            WebView(url: websiteURL, messageHandlerName: jsMessageHandlerName) { message in
                receivedMessage = message
                // Here you would parse the message and call your native functions
                handleWebMessage(message)
            }
            .edgesIgnoringSafeArea(.all) // Makes the WebView fill the screen
        }
    }

    private func handleWebMessage(_ message: String) {
        // Parse the message (e.g., JSON string) and trigger native actions
        print("Native app handling message: \(message)")

        // Example: If the web sends a JSON string like '{"action": "camera", "data": "photo"}'
        if let data = message.data(using: .utf8) {
            if let json = try? JSONSerialization.jsonObject(with: data, options: []) as? [String: Any],
               let action = json["action"] as? String {
                switch action {
                case "camera":
                    print("Received camera request from web. Implementing native camera logic...")
                    // Call your native camera API here
                    break
                case "notifications":
                    print("Received push notification request from web. Implementing native notification logic...")
                    // Call your native push notification registration here
                    break
                case "inAppPurchase":
                    if let productId = json["productId"] as? String {
                        print("Received IAP request for product: \(productId). Implementing native IAP logic...")
                        // Call your native in-app purchase flow here
                    }
                    break
                default:
                    print("Unknown action received: \(action)")
                }
            }
        }
    }
}

